import time
from collections import defaultdict
from flask import request, jsonify

class RateLimiter:
    def __init__(self, app=None, default_limit=100, window=3600):
        self.limits = {}
        self.default_limit = default_limit
        self.window = window
        self._requests = defaultdict(list)
        if app:
            self.init_app(app)

    def init_app(self, app):
        app.before_request(self._check_rate_limit)

    def limit(self, endpoint, max_requests, window=None):
        self.limits[endpoint] = {'max': max_requests, 'window': window or self.window}

    def _check_rate_limit(self):
        key = f"{request.remote_addr}:{request.endpoint}"
        config = self.limits.get(request.endpoint, {'max': self.default_limit, 'window': self.window})
        now = time.time()
        self._requests[key] = [t for t in self._requests[key] if now - t < config['window']]
        if len(self._requests[key]) >= config['max']:
            return jsonify({'error': 'Rate limit exceeded'}), 429
        self._requests[key].append(now)

